    def countNumbers(self, l, r, b):
        MOD = 10**9 + 7
        def non_dec(x):
            d = []
            if x == 0:
                d = [0]
            else:
                t = x
                while t > 0:
                    d.append(t % b)
                    t //= b
                d.reverse()
            return all(d[i] <= d[i+1] for i in range(len(d)-1))
        lo = int(l)
        hi = int(r)
        cnt = 0
        for x in range(lo, hi + 1):
            if non_dec(x):
                cnt += 1
        return cnt % MOD

