from functools import lru_cache

class Solution:
    def countNumbers(self, l, r, b):
        MOD = 10**9 + 7
        def to_base(x):
            if x == 0:
                return [0]
            d = []
            while x > 0:
                d.append(x % b)
                x //= b
            return d[::-1]
        def f(N):
            if N < 0:
                return 0
            digs = to_base(N)
            L = len(digs)
            @lru_cache(maxsize=None)
            def dp(pos, last, tight, started):
                if pos == L:
                    return 1
                limit = digs[pos] if tight else (b - 1)
                total = 0
                for d in range(0, limit + 1):
                    ntight = tight and (d == limit)
                    if not started:
                        if d == 0:
                            total += dp(pos + 1, 0, ntight, False)
                        else:
                            total += dp(pos + 1, d, ntight, True)
                    else:
                        if d >= last:
                            total += dp(pos + 1, d, ntight, True)
                    total %= MOD
                return total
            res = dp(0, 0, True, False)
            dp.cache_clear()
            return res
        return (f(int(r)) - f(int(l) - 1)) % MOD

