var countNumbers = function(l, r, b) {
    const MOD = 1000000007n;
    const B = BigInt(b);
    const toBase = (x) => {
        if (x === 0n) return [0];
        const d = [];
        while (x > 0n) { d.push(Number(x % B)); x /= B; }
        return d.reverse();
    };
    const f = (N) => {
        if (N < 0n) return 0n;
        const digs = toBase(N);
        const L = digs.length;
        const memo = new Map();
        const dp = (pos, last, tight, started) => {
            if (pos === L) return 1n;
            const key = pos + ',' + last + ',' + (tight ? 1 : 0) + ',' + (started ? 1 : 0);
            if (memo.has(key)) return memo.get(key);
            const limit = tight ? digs[pos] : (b - 1);
            let total = 0n;
            for (let d = 0; d <= limit; d++) {
                const ntight = tight && (d === limit);
                if (!started) {
                    if (d === 0) total += dp(pos + 1, 0, ntight, false);
                    else total += dp(pos + 1, d, ntight, true);
                } else {
                    if (d >= last) total += dp(pos + 1, d, ntight, true);
                }
                total %= MOD;
            }
            memo.set(key, total);
            return total;
        };
        return dp(0, 0, true, false);
    };
    const ans = ((f(BigInt(r)) - f(BigInt(l) - 1n)) % MOD + MOD) % MOD;
    return Number(ans);
};
